WITH REGISTROFECHA AS (SELECT COMPANIA, CODIGO, CASE WHEN TIPOREGISTRO IN ('REG') THEN FECHAREGISTRO ELSE FECHA_ACTUALIZACION END FECHAREG FROM PROYECTOS ) SELECT PROYECTOS.COMPANIA, PROYECTOS.CREATED_BY CREADOR, CASE WHEN USUARIO.NOMBRE1 IN ('') THEN '' ELSE USUARIO.NOMBRE1 ||' ' END|| CASE WHEN USUARIO.NOMBRE2 IN ('') THEN '' ELSE USUARIO.NOMBRE2 ||' ' END || CASE WHEN USUARIO.APELLIDO1 IN ('') THEN '' ELSE USUARIO.APELLIDO1 ||' 'END || CASE WHEN USUARIO.APELLIDO2 IN ('') THEN '' ELSE USUARIO.APELLIDO2  ||' ' END NOMBRELARGO, PROYECTOS.CODIGO, SUBSTR(PROYECTOS.CODIGOBPIM,1,4)||'-'||SUBSTR(PROYECTOS.CODIGOBPIM,4,6)||'-'||SUBSTR(PROYECTOS.CODIGOBPIM,-4,4) AS BPIM_NO, PROYECTOS.CODIGOBPIM, PROYECTOS.NOMBREPROYECTO, TO_CHAR(PROYECTOS.VALORTOTAL, '99G999G999G999', 'NLS_NUMERIC_CHARACTERS = ".,"') AS VALOR_PROYECTO, PROYECTOS.COMPANIA||'-'||PROYECTOS.VIGENCIAINICIO AS PROYECTO_VIGENCIA, DEPENDENCIA.NOMBRE      NOMBRE_DEPENDENCIA, PARAMETRO.VALOR PLAN_DESARROLLO, (SELECT TO_CHAR(BP_PLAN_INDICATIVO.DESCRIPCION)"PLAN_INDICATIVO" FROM BP_PLAN_INDICATIVO WHERE BP_PLAN_INDICATIVO.ID=(SELECT SUBSTR(BP_PROYECTO_PLAN_INDICATIVO.ID_PLAN_P,1,(SELECT TO_NUMBER(PARAMETRO.VALOR)"id_plan"FROM PARAMETRO LEFT JOIN PROYECTOS ON PROYECTOS.COMPANIA=PARAMETRO.COMPANIA WHERE PARAMETRO.NOMBRE='NUMERO DE DIGITOS EJE' AND PARAMETRO.COMPANIA=s$compania$s AND PROYECTOS.CODIGO='s$codigo$s'))"ID" FROM BP_PROYECTO_PLAN_INDICATIVO WHERE BP_PROYECTO_PLAN_INDICATIVO.COMPANIA=s$compania$s AND BP_PROYECTO_PLAN_INDICATIVO.PROYECTO='s$codigo$s' AND BP_PLAN_INDICATIVO.VIGENCIA_INICIAL >= s$vigenciaInicioCons$s  AND  BP_PLAN_INDICATIVO.VIGENCIA_FINAL >= s$vigenciaFinCons$s))AS LINEA, (SELECT TO_CHAR(BP_PLAN_INDICATIVO.DESCRIPCION)"PLAN_INDICATIVO" FROM BP_PLAN_INDICATIVO WHERE BP_PLAN_INDICATIVO.ID=(SELECT SUBSTR(BP_PROYECTO_PLAN_INDICATIVO.ID_PLAN_P,1,(SELECT TO_NUMBER(PARAMETRO.VALOR)"id_plan"FROM PARAMETRO LEFT JOIN PROYECTOS ON PROYECTOS.COMPANIA=PARAMETRO.COMPANIA WHERE PARAMETRO.NOMBRE='NUMERO DE DIGITOS SECTOR' AND PARAMETRO.COMPANIA=s$compania$s AND PROYECTOS.CODIGO='s$codigo$s'))"ID" FROM BP_PROYECTO_PLAN_INDICATIVO WHERE BP_PROYECTO_PLAN_INDICATIVO.COMPANIA=s$compania$s AND BP_PROYECTO_PLAN_INDICATIVO.PROYECTO='s$codigo$s' AND BP_PLAN_INDICATIVO.VIGENCIA_INICIAL >= s$vigenciaInicioCons$s  AND  BP_PLAN_INDICATIVO.VIGENCIA_FINAL >= s$vigenciaFinCons$s))AS SECTOR, (SELECT TO_CHAR(BP_PLAN_INDICATIVO.DESCRIPCION)"PLAN_INDICATIVO" FROM BP_PLAN_INDICATIVO WHERE BP_PLAN_INDICATIVO.ID=(SELECT SUBSTR(BP_PROYECTO_PLAN_INDICATIVO.ID_PLAN_P,1,(SELECT TO_NUMBER(PARAMETRO.VALOR)"id_plan"FROM PARAMETRO LEFT JOIN PROYECTOS ON PROYECTOS.COMPANIA=PARAMETRO.COMPANIA WHERE PARAMETRO.NOMBRE='NUMERO DE DIGITOS PROGRAMA' AND PARAMETRO.COMPANIA=s$compania$s AND PROYECTOS.CODIGO='s$codigo$s'))"ID" FROM BP_PROYECTO_PLAN_INDICATIVO WHERE BP_PROYECTO_PLAN_INDICATIVO.COMPANIA=s$compania$s AND BP_PROYECTO_PLAN_INDICATIVO.PROYECTO='s$codigo$s' AND BP_PLAN_INDICATIVO.VIGENCIA_INICIAL >= s$vigenciaInicioCons$s  AND  BP_PLAN_INDICATIVO.VIGENCIA_FINAL >= s$vigenciaFinCons$s))AS PROGRAMA, (SELECT PARAMETRO.VALOR FROM PARAMETRO WHERE PARAMETRO.NOMBRE='JEFE BANCO PROYECTOS' AND PARAMETRO.COMPANIA=s$compania$s AND PROYECTOS.CODIGO='s$codigo$s') AS JEFE_PROYECTOS, (SELECT PARAMETRO.VALOR FROM PARAMETRO WHERE PARAMETRO.NOMBRE='CARGO JEFE BANCO PROYECTOS' AND PARAMETRO.COMPANIA=s$compania$s AND PROYECTOS.CODIGO='s$codigo$s') AS CARGO_JEFE_PROYECTOS, (SELECT PARAMETRO.VALOR FROM PARAMETRO WHERE PARAMETRO.NOMBRE='DATOS COORDINADOR BANCO PROYECTOS' ) AS DATOS_CORDINADOR, 'Florencia, ' || EXTRACT(DAY FROM REGISTROFECHA.FECHAREG) || ' De ' || PCK_SYSMAN_UTL.FC_NOMBRE_MES(EXTRACT(MONTH FROM REGISTROFECHA.FECHAREG)) || ' De ' || EXTRACT(YEAR FROM REGISTROFECHA.FECHAREG) FECHAF, EXTRACT(DAY FROM REGISTROFECHA.FECHAREG) || ' dias del mes de '|| PCK_SYSMAN_UTL.FC_NOMBRE_MES(EXTRACT(MONTH FROM REGISTROFECHA.FECHAREG)) || ' De '|| EXTRACT(YEAR FROM REGISTROFECHA.FECHAREG) FECHAH, COMPONENTES.NOMBRECOMPONENTE NOMBRE_C FROM PROYECTOS LEFT JOIN DEPENDENCIA ON PROYECTOS.COMPANIA     = DEPENDENCIA.COMPANIA AND PROYECTOS.DEPENDENCIA = DEPENDENCIA.CODIGO LEFT JOIN PARAMETRO ON PARAMETRO.COMPANIA     = DEPENDENCIA.COMPANIA AND PARAMETRO.NOMBRE='PLAN DE DESARROLLO'LEFT JOIN RESPONSABLE ON PROYECTOS.COMPANIA     = RESPONSABLE.COMPANIA AND PROYECTOS.RESPONSABLE = RESPONSABLE.CEDULA LEFT JOIN TERCERO ON RESPONSABLE.COMPANIA = TERCERO.COMPANIA AND RESPONSABLE.CEDULA = TERCERO.NIT AND RESPONSABLE.SUCURSAL = TERCERO.SUCURSAL LEFT JOIN REGISTROFECHA ON PROYECTOS.COMPANIA = REGISTROFECHA.COMPANIA AND PROYECTOS.CODIGO = REGISTROFECHA.CODIGO INNER JOIN USUARIO ON PROYECTOS.CREATED_BY = USUARIO.CODIGO INNER JOIN COMPONENTES ON PROYECTOS.COMPANIA     = COMPONENTES.COMPANIA AND PROYECTOS.CODIGO = COMPONENTES.CODIGOPROYECTO WHERE PROYECTOS.COMPANIA =s$compania$s AND PROYECTOS.CODIGO='s$codigo$s'